    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails(
            "TRK-001",
            "In Transit",
            "Chicago, IL",
            DateTimeOffset.UtcNow.AddDays(2),
            new List<StatusUpdate>
            {
                new(DateTimeOffset.UtcNow.AddDays(-3), "Package picked up from sender"),
                new(DateTimeOffset.UtcNow.AddDays(-2), "Arrived at sorting facility - New York, NY"),
                new(DateTimeOffset.UtcNow.AddDays(-1), "Departed sorting facility - New York, NY"),
                new(DateTimeOffset.UtcNow.AddHours(-6), "Arrived at regional hub - Chicago, IL"),
            }),
        ["TRK-002"] = new ShipmentDetails(
            "TRK-002",
            "Delivered",
            "San Francisco, CA",
            DateTimeOffset.UtcNow.AddDays(-1),
            new List<StatusUpdate>
            {
                new(DateTimeOffset.UtcNow.AddDays(-5), "Package picked up from sender"),
                new(DateTimeOffset.UtcNow.AddDays(-4), "In transit to destination"),
                new(DateTimeOffset.UtcNow.AddDays(-2), "Out for delivery"),
                new(DateTimeOffset.UtcNow.AddDays(-1), "Delivered - Left at front door"),
            }),
        ["TRK-003"] = new ShipmentDetails(
            "TRK-003",
            "Processing",
            "Seattle, WA",
            DateTimeOffset.UtcNow.AddDays(5),
            new List<StatusUpdate>
            {
                new(DateTimeOffset.UtcNow.AddHours(-2), "Label created, awaiting pickup"),
            }),
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
    }
}

